mapping:
(
  $cell := function($value) { $exists($value) ? $value : "" };
  $joinValues := function($values) {
    $exists($values) ? $join($values[$exists($) and $string($) != ""].$string($), " | ") : ""
  };
  $authorName := function($entry) {
    $trim(($entry.author.last_name ? $entry.author.last_name : "") & ($entry.author.first_name ? ", " & $entry.author.first_name : ""))
  };
  $sumValues := function($values) {
    $exists($values) ? $sum($values[$exists($)].$number($)) : ""
  };
  $amountWithVat := function($item) {
    ($exists($item.euro_value) ? $item.euro_value : 0) + ($exists($item.vat) ? $item.vat : 0)
  };
  $costTypeTotals := function($items) {(
    $labels := $distinct($items.cost_type.label);
    $exists($labels) ? $merge($labels.(
      $label := $;
      {($label): $sum($items[cost_type.label = $label].$amountWithVat($))}
    )) : {}
  )};
  $merge([
    {
      "id": $cell(id),
      "locked": $cell(locked),
      "status": $cell(status),
      "title": $cell(title),
      "doi": $cell(doi),
      "link": $cell(link),
      "authors": $cell(authors),
      "authors_inst": $joinValues(authorPublications.$authorName($)),
      "institutes": $joinValues(authorPublications.institute.label),
      "corr_authors": $joinValues(authorPublications[corresponding].$authorName($)),
      "corr_institutes": $joinValues(authorPublications[corresponding].institute.label),
      "greater_entity": $cell(greater_entity.label),
      "pub_date": $cell(pub_date),
      "publisher": $cell(publisher.label),
      "language": $cell(language.label),
      "oa_category": $cell(oa_category.label),
      "pub_type": $cell(pub_type.label),
      "funders": $joinValues(funders.label),
      "contract": $cell(contract.label),
      "cost_approach": $cell(cost_approach),
      "cost_approach_currency": $cell(cost_approach_currency),
      "invoice_numbers": $joinValues(invoices.number),
      "net_costs": $sumValues(invoices.cost_items.euro_value),
      "paid_amount": $sumValues(invoices.booking_amount),
      "cost_center": $joinValues(invoices.cost_center.label),
      "data_source": $cell(dataSource),
      "second_pub": $cell(second_pub),
      "add_info": $cell(add_info),
      "import_date": $cell(import_date),
      "edit_date": $cell(edit_date)
    },
    $costTypeTotals(invoices.cost_items)
  ])
)
